-- ----------------------------
-- Table structure for stock_price
-- ----------------------------
DROP TABLE IF EXISTS `stock_price`;
CREATE TABLE `stock_price`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `ticker` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '代码',
  `type` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'STOCK' COMMENT '类型：STOCK-股票，BOND-债券',
  `ts` date NOT NULL COMMENT '日期',
  `open` decimal(10, 4) NOT NULL COMMENT '开盘价',
  `high` decimal(10, 4) NOT NULL COMMENT '最高价',
  `low` decimal(10, 4) NOT NULL COMMENT '最低价',
  `close` decimal(10, 4) NOT NULL COMMENT '收盘价',
  `volume` bigint NOT NULL COMMENT '成交量',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_ticker_ts_type`(`ticker` ASC, `ts` ASC, `type` ASC) USING BTREE,
  INDEX `idx_ticker`(`ticker` ASC) USING BTREE,
  INDEX `idx_ts`(`ts` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1000 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;

