-- Records of stock_price
-- ----------------------------

-- ----------------------------
-- Table structure for stock_trade
-- ----------------------------
DROP TABLE IF EXISTS `stock_trade`;
CREATE TABLE `stock_trade`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `ticker` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '股票代码',
  `trade_type` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'BUY / SELL',
  `price` decimal(10, 4) NOT NULL COMMENT '成交价格',
  `quantity` int NOT NULL COMMENT '数量',
  `amount` decimal(15, 4) NOT NULL COMMENT '成交总金额',
  `ts` datetime NOT NULL COMMENT '交易时间',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_ticker`(`ticker` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

