-- ----------------------------
-- Procedure structure for generate_stock_data
-- ----------------------------
DROP PROCEDURE IF EXISTS `generate_stock_data`;
delimiter ;;
CREATE PROCEDURE `generate_stock_data`()
BEGIN
    DECLARE i INT DEFAULT 0;
    DECLARE base_price DECIMAL(10,4);
    DECLARE curr_price DECIMAL(10,4);
    DECLARE ticker_val VARCHAR(10);
    DECLARE rand_val DOUBLE;

    WHILE i < 1000 DO
        
        -- 随机选股票
        SET rand_val = RAND();
        IF rand_val < 0.33 THEN
            SET ticker_val = 'TSLA';
            SET base_price = 250;
        ELSEIF rand_val < 0.66 THEN
            SET ticker_val = 'AAPL';
            SET base_price = 180;
        ELSE
            SET ticker_val = 'NVDA';
            SET base_price = 900;
        END IF;

        -- 生成价格波动
        SET curr_price = base_price + (RAND() - 0.5) * 10;

            ticker, ts, open, high, low, close, volume
        ) VALUES (
            ticker_val,
            NOW() - INTERVAL (1000 - i) MINUTE,

            curr_price,
            curr_price + RAND() * 5,
            curr_price - RAND() * 5,
            curr_price + (RAND() - 0.5) * 2,

            FLOOR(1000 + RAND() * 10000)
        );

        SET i = i + 1;
    END WHILE;
END
;;
delimiter ;

SET FOREIGN_KEY_CHECKS = 1;
